    /// <summary>
    /// Computes the normalized (forward-slash) parent of a relative path.
    /// Returns <c>null</c> when <paramref name="relative"/> is the root (empty),
    /// or the empty string when the path is a direct child of the root.
    /// </summary>
    private static string? ComputeParent(string relative)
    {
        if (string.IsNullOrEmpty(relative))
        {
            return null;
        }

        var separatorIndex = relative.LastIndexOf('/');
        if (separatorIndex < 0)
        {
            return string.Empty;
        }

        return relative.Substring(0, separatorIndex);
    }

    /// <summary>
    /// Sorts directories before files, ordering each group by name using
    /// <see cref="StringComparison.OrdinalIgnoreCase"/>.
    /// </summary>
    private static int CompareEntries(FileEntryDto a, FileEntryDto b)
    {
        if (a.IsDirectory != b.IsDirectory)
        {
            return a.IsDirectory ? -1 : 1;
        }

        return string.Compare(a.Name, b.Name, StringComparison.OrdinalIgnoreCase);
    }

    /// <summary>
    /// Recursively copies a directory tree, preserving structure. Existing
    /// files are not overwritten, matching the no-overwrite contract of
    /// <see cref="File.Copy(string, string, bool)"/>.
    /// </summary>
    private static void CopyDirectory(string source, string destination)
    {
        Directory.CreateDirectory(destination);

        foreach (var file in Directory.GetFiles(source))
        {
            File.Copy(file, Path.Combine(destination, Path.GetFileName(file)), overwrite: false);
        }

        foreach (var directory in Directory.GetDirectories(source))
        {
            CopyDirectory(directory, Path.Combine(destination, Path.GetFileName(directory)));
        }
    }
}

using System;
using System.Linq;
using System.Reflection;
using Xunit;

namespace TestProject.Tests;

/// <summary>
/// Tests for <c>TestProject.Configuration.FileServiceOptions</c>, the
/// strongly-typed options object bound from the "FileService" configuration
/// section that configures the server-side home directory.
///
/// This type was relocated from the root <c>TestProject</c> namespace into
/// <c>TestProject.Configuration</c>. Because the type's full name changes as a
/// result of that move, these tests resolve the type by <strong>reflection</strong>
/// against the main assembly rather than via a direct C# reference. This keeps the
/// file compilable both before and after the relocation, while the assertions pin
/// down the expected end state:
/// <list type="bullet">
/// <item>The type lives in <c>TestProject.Configuration</c> (and only there).</item>
/// <item>It is a public class with a public parameterless constructor and a
/// mutable <c>string HomeDirectory</c> property defaulting to <c>"Home"</c>.</item>
/// </list>
/// The behaviors themselves are unchanged by the move; these tests verify the type
/// arrives at its new home with its contract intact, and that no duplicate
/// root-namespace definition lingers.
/// </summary>
public class FileServiceOptionsTests
{
    private const string ExpectedFullName = "TestProject.Configuration.FileServiceOptions";
    private const string ExpectedNamespace = "TestProject.Configuration";
    private const string ExpectedRootFullName = "TestProject.FileServiceOptions";
    private const string HomeDirectoryProperty = "HomeDirectory";

    // Program is declared in the root TestProject namespace and is unaffected by
    // the move, so it is a stable anchor for obtaining the main assembly.
    private static Assembly MainAssembly => typeof(Program).Assembly;

    /// <summary>
    /// Resolves <c>FileServiceOptions</c> by its fully-qualified name, asserting
    /// that it exists in the <c>TestProject.Configuration</c> namespace.
    /// </summary>
    private static Type GetOptionsType()
    {
        var type = MainAssembly.GetType(ExpectedFullName);
        Assert.NotNull(type);
        return type!;
    }

    // =====================================================================
    // Type identity / namespace placement
    // =====================================================================

    [Fact]
    public void FileServiceOptions_LivesInTestProjectConfigurationNamespace()
    {
        var type = GetOptionsType();

        Assert.Equal(ExpectedNamespace, type.Namespace);
        Assert.Equal(ExpectedFullName, type.FullName);
    }

    [Fact]
    public void FileServiceOptions_NoLongerDeclaredInRootTestProjectNamespace()
    {
        // The old root-namespace definition must be gone. If it lingers alongside
        // the new one, the two become ambiguous and DI resolution is unreliable.
        var rootType = MainAssembly.GetType(ExpectedRootFullName);

        Assert.Null(rootType);
    }

    [Fact]
    public void Assembly_DeclaresExactlyOne_FileServiceOptions_Type()
    {
        var matches = MainAssembly.GetTypes()
            .Where(t => t.Name == "FileServiceOptions")
            .ToArray();

        var fullNames = string.Join(", ", matches.Select(t => t.FullName));

        Assert.True(matches.Length == 1,
            $"Expected exactly one FileServiceOptions type, but found {matches.Length}: [{fullNames}].");
        Assert.Equal(ExpectedFullName, matches[0].FullName);
    }

    [Fact]
    public void FileServiceOptions_IsAPublicNonAbstractClass()
    {
        var type = GetOptionsType();

        Assert.True(type.IsClass);
        Assert.True(type.IsPublic);
        Assert.False(type.IsAbstract);
    }

    // =====================================================================
    // HomeDirectory contract (unchanged by the move)
    // =====================================================================

    [Fact]
    public void Constructor_DefaultHomeDirectory_IsHome()
    {
        var type = GetOptionsType();
        var instance = Activator.CreateInstance(type);

        Assert.NotNull(instance);
        var value = type.GetProperty(HomeDirectoryProperty)!.GetValue(instance);

        Assert.Equal("Home", value);
    }

    [Theory]
    [InlineData("MyFiles")]
    [InlineData("/var/data/files")]
    [InlineData("Data/Files")]
    [InlineData("")]
    [InlineData("   ")]
    public void HomeDirectory_RoundTripsArbitraryStringValues(string value)
    {
        var type = GetOptionsType();
        var prop = type.GetProperty(HomeDirectoryProperty);

        Assert.NotNull(prop);
        var instance = Activator.CreateInstance(type);
        Assert.NotNull(instance);

        prop!.SetValue(instance, value);

        Assert.Equal(value, prop.GetValue(instance));
    }

    [Fact]
    public void HomeDirectory_IsPublicMutableStringProperty()
    {
        var type = GetOptionsType();
        var prop = type.GetProperty(HomeDirectoryProperty);

        Assert.NotNull(prop);
        Assert.Equal(typeof(string), prop!.PropertyType);
        Assert.True(prop.CanRead, "HomeDirectory must have a getter.");
        Assert.True(prop.CanWrite, "HomeDirectory must have a setter.");
